mapper.select:
SELECT id, event_type, fingerprint, payload, status, retry_count, create_time, update_time
FROM user_event_outbox
WHERE status = #{status}
ORDER BY update_time ASC
LIMIT #{limit}

mapper.update:
UPDATE user_event_outbox
SET status = 'DONE', update_time = NOW()
WHERE id = #{id}

UPDATE user_event_outbox
SET status = 'FAIL', retry_count = retry_count + 1, update_time = NOW()
WHERE id = #{id}

mapper.delete:
DELETE FROM user_event_outbox
WHERE status = #{status}
  AND update_time < #{before}
